import UIKit
import WebKit

class HybridWebViewController: UIViewController, WKUIDelegate, WKNavigationDelegate, WKScriptMessageHandler {

    var webView: WKWebView!
    let websiteURLString: String = "https://your-mobile-website.com" // Replace with your actual mobile website URL
    let messageHandlerName: String = "hybridApp" // Name for the JavaScript message handler

    override func viewDidLoad() {
        super.viewDidLoad()

        setupWebView()
        loadWebsite()
    }

    private func setupWebView() {
        let contentController = WKUserContentController()
        contentController.add(self, name: messageHandlerName)

        let configuration = WKWebViewConfiguration()
        configuration.userContentController = contentController
        configuration.allowsInlineMediaPlayback = true // Enable inline playback for HTML5 videos

        // Configure preferences for JavaScript
        let preferences = WKPreferences()
        preferences.javaScriptEnabled = true
        preferences.javaScriptCanOpenWindowsAutomatically = true
        configuration.preferences = preferences

        webView = WKWebView(frame: self.view.bounds, configuration: configuration)
        webView.autoresizingMask = [.flexibleWidth, .flexibleHeight]
        webView.uiDelegate = self
        webView.navigationDelegate = self
        self.view.addSubview(webView)
    }

    private func loadWebsite() {
        if let url = URL(string: websiteURLString) {
            let request = URLRequest(url: url)
            webView.load(request)
        }
    }

    // MARK: - WKScriptMessageHandler

    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        if message.name == messageHandlerName {
            // Process messages from the web view
            print("Received message from web: \(message.body)")

            if let body = message.body as? [String: Any],
               let functionName = body["function"] as? String {

                switch functionName {
                case "requestCameraAccess":
                    // Handle camera access request
                    print("Web requested camera access")
                    // Example: Call a native function to request camera access
                    handleCameraAccessRequest()
                case "registerForPushNotifications":
                    // Handle push notification registration
                    print("Web requested push notification registration")
                    // Example: Call a native function to register for push notifications
                    handlePushNotificationRegistration()
                case "initiateInAppPurchase":
                    // Handle in-app purchase
                    print("Web requested in-app purchase")
                    if let productId = body["productId"] as? String {
                        // Example: Call a native function to initiate IAP for productId
                        handleInAppPurchase(productId: productId)
                    }
                case "getDeviceInfo":
                    // Example: Return device info to web
                    sendDeviceInfoToWeb()
                default:
                    print("Unknown function call from web: \(functionName)")
                }
            }
        }
    }

    // MARK: - Native Function Implementations (Examples)

    private func handleCameraAccessRequest() {
        // Implement native camera access logic
        // This would typically involve requesting AVCaptureDevice.requestAccess(for: .video)
        // and then calling a JS function to notify the web view of the result.
        print("NATIVE: Requesting camera access...")
        AVCaptureDevice.requestAccess(for: .video) { granted in
            DispatchQueue.main.async {
                let jsCallback = "window.nativeCameraAccessCallback(\(granted ? "true" : "false"));"
                self.webView.evaluateJavaScript(jsCallback) { result, error in
                    if let error = error {
                        print("Error evaluating JS callback: \(error)")
                    }
                }
            }
        }
    }

    private func handlePushNotificationRegistration() {
        // Implement native push notification registration logic
        // This would involve UNUserNotificationCenter.current().requestAuthorization
        // and then registering for remote notifications.
        print("NATIVE: Registering for push notifications...")
        UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .sound, .badge]) { granted, error in
            DispatchQueue.main.async {
                let jsCallback = "window.nativePushRegistrationCallback(\(granted ? "true" : "false"));"
                self.webView.evaluateJavaScript(jsCallback) { result, error in
                    if let error = error {
                        print("Error evaluating JS callback: \(error)")
                    }
                }
                if granted {
                    UIApplication.shared.registerForRemoteNotifications()
                }
            }
        }
    }

    private func handleInAppPurchase(productId: String) {
        // Implement native in-app purchase logic using StoreKit
        print("NATIVE: Initiating in-app purchase for product ID: \(productId)...")
        // This would involve SKProductRequest, SKPaymentQueue, etc.
        // For demonstration, just simulate a callback
        DispatchQueue.main.asyncAfter(deadline: .now() + 1.0) {
            let success = Bool.random() // Simulate success/failure
            let jsCallback = "window.nativeInAppPurchaseCallback('\(productId)', \(success ? "true" : "false'));"
            self.webView.evaluateJavaScript(jsCallback) { result, error in
                if let error = error {
                    print("Error evaluating JS callback: \(error)")
                }
            }
        }
    }

    private func sendDeviceInfoToWeb() {
        let deviceModel = UIDevice.current.model
        let systemVersion = UIDevice.current.systemVersion
        let appVersion = Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "Unknown"

        let jsObject = """
        {
            "model": "\(deviceModel)",
            "osVersion": "\(systemVersion)",
            "appVersion": "\(appVersion)"
        }
        """
        let jsCallback = "window.nativeDeviceInfoCallback(\(jsObject));"
        webView.evaluateJavaScript(jsCallback) { result, error in
            if let error = error {
                print("Error evaluating JS callback: \(error)")
            } else {
                print("Sent device info to web.")
            }
        }
    }

    // MARK: - WKNavigationDelegate (Optional: for handling navigation events)

    func webView(_ webView: WKWebView, didFinish navigation: WKNavigation!) {
        print("WebView finished loading: \(webView.url?.absoluteString ?? "N/A")")
